import 'package:flutter_riverpod/flutter_riverpod.dart'; import '../../../auth/presentation/providers/auth_providers.dart'; import 'notification_providers.dart';
final notificationControllerProvider=StateNotifierProvider<NotificationController,NotificationControllerState>((ref)=>NotificationController(ref));
class NotificationController extends StateNotifier<NotificationControllerState>{final Ref ref; NotificationController(this.ref):super(const NotificationControllerState()); Future<void> markAsRead(String id) async{state=state.copyWith(isLoading:true); try{await ref.read(notificationRepositoryProvider).markAsRead(id); ref.invalidate(myNotificationsProvider); ref.invalidate(unreadNotificationCountProvider); state=state.copyWith(isLoading:false,success:true,errorMessage:null);}catch(e){state=state.copyWith(isLoading:false,errorMessage:e.toString());}} Future<void> markAllAsRead() async{final user=ref.read(currentUserProvider); if(user==null)return; await ref.read(notificationRepositoryProvider).markAllAsRead(user.uid); ref.invalidate(myNotificationsProvider); ref.invalidate(unreadNotificationCountProvider);}}
class NotificationControllerState{final bool isLoading,success; final String? errorMessage; const NotificationControllerState({this.isLoading=false,this.success=false,this.errorMessage}); NotificationControllerState copyWith({bool? isLoading,bool? success,String? errorMessage})=>NotificationControllerState(isLoading:isLoading??this.isLoading,success:success??this.success,errorMessage:errorMessage);}
